#include <bits/stdc++.h>
using namespace std;
int main(){
    int dp[102][102];
    string a,b;
    while(cin>>a>>b){
        memset(dp,127,sizeof(dp));
        a=" "+a,b=" "+b;
        int n=a.size()-1;
        for(int i=1;i<a.size();i++)dp[i][i]=(a[i]!=b[i]);
        for(int len=2;len<=n;len++)
            for(int l=1;l+len-1<=n;l++){
                int r=l+len-1;
                if(a[l]==b[l] && a[r]==b[r])dp[l][r]=(len==2?0:dp[l+1][r-1]);
                else if(a[l]==b[l])dp[l][r]=dp[l+1][r];
                else if(a[r]==b[r])dp[l][r]=dp[l][r-1];
                else
                    for(int k=l;k<r;k++)dp[l][r]=min(dp[l][r],dp[l][k]+dp[k+1][r]);
            }
        cout<<dp[1][n]<<endl;
    }
    return 0;
}
